const bancoDados = $getWorkflowStaticData('global');
const userId = $('Telegram Trigger').first().json.callback_query.message.chat.id;

const precos = {
  'Homus': 18.00,
  'Quibe Cru': 22.00,
  'Tabule': 16.00,
  'Kafta': 45.00,
  'Charuto': 42.00,
  'Cordeiro': 65.00
};
const precoEsfiha = 8.00;
const precoQuibeAssado = 10.00;

let total = 0;
const pedidos = bancoDados.usuario[userId]?.pedidos || [];
const linhasItens = [];

for (const pedido of pedidos) {
  const entradas = pedido['Entrada']
    ? (Array.isArray(pedido['Entrada']) ? pedido['Entrada'] : pedido['Entrada'].split(',').map(s => s.trim()))
    : [];
  for (const e of entradas) {
    const preco = precos[e] || 0;
    total += preco;
    if (preco > 0) linhasItens.push(`${e}: R$ ${preco.toFixed(2)}`);
  }

  const qtdEsfiha = Number(pedido['Gostaria de quantas Esfihas?']) || 0;
  if (qtdEsfiha > 0) {
    const v = qtdEsfiha * precoEsfiha;
    total += v;
    linhasItens.push(`Esfihas (${qtdEsfiha}x): R$ ${v.toFixed(2)}`);
  }

  const qtdQuibe = Number(pedido['Gostaria de quantos Quibes Assados?']) || 0;
  if (qtdQuibe > 0) {
    const v = qtdQuibe * precoQuibeAssado;
    total += v;
    linhasItens.push(`Quibes Assados (${qtdQuibe}x): R$ ${v.toFixed(2)}`);
  }

  const pratos = pedido['Pratos (selecione ao menos 1)']
    ? (Array.isArray(pedido['Pratos (selecione ao menos 1)']) ? pedido['Pratos (selecione ao menos 1)'] : pedido['Pratos (selecione ao menos 1)'].split(',').map(s => s.trim()))
    : [];
  for (const p of pratos) {
    const preco = precos[p] || 0;
    total += preco;
    if (preco > 0) linhasItens.push(`${p}: R$ ${preco.toFixed(2)}`);
  }
}

bancoDados.usuario[userId].totalPedido = total;

return [{ json: { userId, total, totalFormatado: `R$ ${total.toFixed(2)}`, itens: linhasItens } }];

