parameters.jsCode:
const db = $getWorkflowStaticData('global');
const { data, hora, pessoas } = $input.first().json.query;

if (!db.mesas) {
  db.mesas = [
    { id: 1, capacidade: 2, tipo: 'Salão principal', reservas: [] },
    { id: 2, capacidade: 2, tipo: 'Varanda',         reservas: [] },
    { id: 3, capacidade: 4, tipo: 'Salão principal', reservas: [] },
    { id: 4, capacidade: 4, tipo: 'Salão principal', reservas: [] },
    { id: 5, capacidade: 4, tipo: 'Jardim interno',  reservas: [] },
    { id: 6, capacidade: 6, tipo: 'Salão VIP',       reservas: [] },
    { id: 7, capacidade: 6, tipo: 'Jardim interno',  reservas: [] },
    { id: 8, capacidade: 8, tipo: 'Salão VIP',       reservas: [] }
  ];
}

const mesas = db.mesas.map(mesa => {
  const ocupada = mesa.reservas.some(r => r.data === data && r.hora === hora);
  return {
    id: mesa.id,
    capacidade: mesa.capacidade,
    tipo: mesa.tipo,
    ocupada
  };
});

return [{ json: { mesas } }];

const db = $getWorkflowStaticData('global');
const body = $input.first().json.body;
const { mesaId, data, hora, pessoas, userId } = body;

// Encontrar a mesa
const mesa = (db.mesas || []).find(m => m.id == mesaId);

if (!mesa) {
  return [{ json: { sucesso: false, mensagem: 'Mesa não encontrada.' } }];
}

// Checar conflito
const conflito = mesa.reservas.some(r => r.data === data && r.hora === hora);
if (conflito) {
  return [{ json: { sucesso: false, mensagem: 'Mesa já reservada neste horário.' } }];
}

// Registrar
mesa.reservas.push({ data, hora, pessoas, userId, criadoEm: new Date().toISOString() });

return [{ json: { sucesso: true, mesaId, data, hora, pessoas, userId } }];

